CREATE OR REPLACE FUNCTION OFSERM.ABL_BANKING_LEASES_EXPOSURE_DATA_CREATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_BANKING_EXPOSURES(N_COUNTRY_SKEY,N_CREDIT_STATUS_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,N_GUARANTEE_SCHEME_SKEY,N_ISSUE_SKEY,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_REG_CAP_GUARANTEE_SCH_SKEY,N_REPAYMENT_TYPE_SKEY,F_EXP_FOR_SALE_IND,N_CURR_12M_ECL,N_EXPOSURE_AMOUNT,N_GROUP_ASSET_SIZE,N_LOSS_ALLOWANCE_LIFE_ECL,N_ORIGINAL_MATURITY,N_PARENT_ACCT_SKEY,N_RESIDUAL_MATURITY,N_RUN_PARAMETER_SETUP_SKEY,N_RUN_SKEY,N_CUST_ANNUAL_SALES,N_SHAREHOLDING_PERCENT,V_APPROACH_TYPE,V_EXP_RCY_CODE,V_PRODUCT_BOOK_CODE,N_ENTITY_SKEY,F_CASH_POOL_DAILY_TRANSFER,F_CASH_POOL_LEGAL_ENFORCEABLE,F_CREDIT_IMPAIRMENT_FLAG,F_FINANCIAL_ASSET_IFRS9_FLAG,N_CCF_OWN_ESTIMATE,N_EFF_MATURITY,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,N_PROVISION_AMOUNT,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,D_EXPOSURE_START_DATE,D_EXPOSURE_END_DATE,F_EXP_DEFAULTED_FLAG,F_PAST_DUE_FLAG,F_EXP_REV_FLAG,F_SECURITIZED_FLAG,N_DELQ_DAYS,N_LOAD_RUN_ID,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_CREDIT_STATUS.N_CREDIT_STATUS_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_GUARANTEE_SCHEME.N_GUARANTEE_SCHEME_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_REG_CAP_GUARANTEE_SCHEME.N_REG_CAP_GUARANTEE_SCH_SKEY),to_char(DIM_REPAYMENT_TYPE.N_REPAYMENT_TYPE_SKEY),CASE WHEN COALESCE(STG_LEASES_CONTRACTS.V_HOLDING_TYPE,'X') = 'AFS' THEN 'Y' ELSE 'N' END,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*STG_LEASES_CONTRACTS.N_EOP_BAL,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,DAYS_BETWEEN(STG_LEASES_CONTRACTS.D_LEASE_START_DATE,D_MATURITY_DATE,V_DAY_COUNT_IND),DIM_PARENT_EXPOSURE.N_ACCT_SKEY,DAYS_BETWEEN(STG_LEASES_CONTRACTS.FIC_MIS_DATE, D_MATURITY_DATE,V_DAY_COUNT_IND),CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY ELSE NULL END,'870',FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE ELSE NULL END,RUN_EXE_PARAMETERS_RCY.V_PARAM_VALUE_CODE,'B',to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),FSI_ACCT_MODELING_INFO.F_CASH_POOL_DAILY_TRANSFER,FSI_ACCT_MODELING_INFO.F_CASH_POOL_LEGAL_ENFORCEABLE,FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE),to_char(FSI_ACCT_MODELING_INFO.N_EFF_MATURITY),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_PROVISION_AMOUNT),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),STG_LEASES_CONTRACTS.D_LEASE_START_DATE,STG_LEASES_CONTRACTS.D_MATURITY_DATE,STG_LEASES_CONTRACTS.F_EXP_DEFAULTED_FLAG,STG_LEASES_CONTRACTS.F_PAST_DUE_FLAG,STG_LEASES_CONTRACTS.F_REVOLVE_IND,STG_LEASES_CONTRACTS.F_SECURITIZED_FLAG,to_char(STG_LEASES_CONTRACTS.N_DELINQUENT_DAYS),to_char(STG_LEASES_CONTRACTS.N_LOAD_RUN_ID),STG_LEASES_CONTRACTS.V_CCY_CODE FROM STG_LEASES_CONTRACTS LEFT OUTER JOIN DIM_CREDIT_STATUS ON STG_LEASES_CONTRACTS.v_Credit_Status_Cd = DIM_CREDIT_STATUS.V_CREDIT_STATUS AND STG_LEASES_CONTRACTS.FIC_MIS_DATE BETWEEN DIM_CREDIT_STATUS.D_RECORD_START_DATE AND DIM_CREDIT_STATUS.D_RECORD_END_DATE LEFT OUTER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = STG_LEASES_CONTRACTS.FIC_MIS_DATE LEFT OUTER JOIN DIM_EXPOSURE ON STG_LEASES_CONTRACTS.V_ACCOUNT_NUMBER = DIM_EXPOSURE.V_EXPOSURE_ID AND STG_LEASES_CONTRACTS.fic_mis_date BETWEEN DIM_EXPOSURE.d_record_start_date AND DIM_EXPOSURE.d_record_end_date LEFT OUTER JOIN DIM_EXPOSURE DIM_PARENT_EXPOSURE ON STG_LEASES_CONTRACTS.V_PARENT_EXPOSURE_ID = DIM_PARENT_EXPOSURE.V_EXPOSURE_ID AND STG_LEASES_CONTRACTS.FIC_MIS_DATE BETWEEN DIM_PARENT_EXPOSURE.d_record_start_date AND DIM_PARENT_EXPOSURE.d_record_end_date LEFT OUTER JOIN DIM_PARTY ON STG_LEASES_CONTRACTS.V_CUST_REF_CODE = DIM_PARTY.v_Party_Id AND STG_LEASES_CONTRACTS.fic_mis_date BETWEEN DIM_PARTY.d_record_start_date AND DIM_PARTY.d_record_end_date INNER JOIN DIM_PARTY_TYPE ON DIM_PARTY.V_PARTY_TYPE = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND STG_LEASES_CONTRACTS.fic_mis_date BETWEEN DIM_PARTY_TYPE.d_record_start_date AND DIM_PARTY_TYPE.d_record_end_date LEFT OUTER JOIN DIM_PRODUCT ON STG_LEASES_CONTRACTS.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND STG_LEASES_CONTRACTS.fic_mis_date BETWEEN DIM_PRODUCT.d_record_start_date AND DIM_PRODUCT.d_record_end_date LEFT OUTER JOIN DIM_LOB ON STG_LEASES_CONTRACTS.v_line_code = DIM_LOB.V_LOB_CODE AND STG_LEASES_CONTRACTS.fic_mis_date BETWEEN DIM_LOB.d_record_start_date AND DIM_LOB.d_record_end_date LEFT OUTER JOIN DIM_GEOGRAPHY ON coalesce(DIM_PARTY.V_BRANCH_CODE, 'MSG') = DIM_GEOGRAPHY.V_ACCT_BRANCH_CODE AND STG_LEASES_CONTRACTS.fic_mis_date BETWEEN DIM_GEOGRAPHY.d_record_start_date AND DIM_GEOGRAPHY.d_record_end_date LEFT OUTER JOIN DIM_INDUSTRY ON DIM_INDUSTRY.V_D_CUST_INDUSTRY = coalesce(DIM_PARTY.V_INDUSTRY_CODE, 'MSG') AND STG_LEASES_CONTRACTS.fic_mis_date BETWEEN DIM_INDUSTRY.d_record_start_date AND DIM_INDUSTRY.d_record_end_date LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.V_GAAP_CODE = STG_LEASES_CONTRACTS.V_GAAP_CODE AND STG_LEASES_CONTRACTS.FIC_MIS_DATE BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE INNER JOIN ( FCT_ENTITY_INFO LEFT OUTER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.n_basel_cap_consl_appr_skey = FCT_ENTITY_INFO.n_basel_cap_consl_appr_skey ) ON STG_LEASES_CONTRACTS.v_lv_code = FCT_ENTITY_INFO.v_entity_code LEFT OUTER JOIN DIM_RUN ON DIM_RUN.n_run_skey = '870' LEFT OUTER JOIN DIM_ISSUE ON STG_LEASES_CONTRACTS.v_account_number = DIM_ISSUE.v_issue_code AND STG_LEASES_CONTRACTS.fic_mis_date BETWEEN DIM_ISSUE.d_record_start_date AND DIM_ISSUE.d_record_end_date LEFT OUTER JOIN FSI_CAP_PARTY_FINANCIALS ON FSI_CAP_PARTY_FINANCIALS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_CAP_PARTY_FINANCIALS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_CAP_PARTY_FINANCIALS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY LEFT OUTER JOIN ( RUN_EXE_PARAMETERS INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE AND RUN_EXE_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY ) ON RUN_EXE_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' LEFT OUTER JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT OUTER JOIN DIM_LOCATION ON DIM_LOCATION.V_LOCATION_CODE = DIM_PARTY.V_LOCATION_CODE AND STG_LEASES_CONTRACTS.FIC_MIS_DATE BETWEEN DIM_LOCATION.D_RECORD_START_DATE AND DIM_LOCATION.D_RECORD_END_DATE LEFT OUTER JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_LEASES_CONTRACTS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION A_FSI_CAP_CURRENCY_CONVERSION ON A_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = A_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND A_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION B_FSI_CAP_CURRENCY_CONVERSION ON B_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = B_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND B_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_GROUP_CCY_CODE LEFT OUTER JOIN FSI_ACCT_MODELING_INFO ON FSI_ACCT_MODELING_INFO.V_EXPOSURE_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND STG_LEASES_CONTRACTS.FIC_MIS_DATE BETWEEN FSI_ACCT_MODELING_INFO.D_RECORD_START_DATE AND FSI_ACCT_MODELING_INFO.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' AND FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG = 'N' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN DIM_COUNTRY ON STG_LEASES_CONTRACTS.V_COUNTRY_ID = DIM_COUNTRY.V_COUNTRY_ID AND STG_LEASES_CONTRACTS.FIC_MIS_DATE BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT OUTER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'BNK_NON_SEC_EXP' LEFT OUTER JOIN DIM_GUARANTEE_SCHEME ON DIM_GUARANTEE_SCHEME.V_GUARANTEE_SCHEME_CODE = STG_LEASES_CONTRACTS.V_GUARANTEE_SCHEME_CODE AND STG_LEASES_CONTRACTS.FIC_MIS_DATE BETWEEN DIM_GUARANTEE_SCHEME.D_RECORD_START_DATE AND DIM_GUARANTEE_SCHEME.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_GUAR_SCHEME_RECLASS ON FSI_CAP_GUAR_SCHEME_RECLASS.N_GUARANTEE_SCHEME_SKEY = DIM_GUARANTEE_SCHEME.N_GUARANTEE_SCHEME_SKEY AND FSI_CAP_GUAR_SCHEME_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_CAP_GUAR_SCHEME_RECLASS.N_RUN_SKEY = '870' LEFT OUTER JOIN DIM_REG_CAP_GUARANTEE_SCHEME ON DIM_REG_CAP_GUARANTEE_SCHEME.N_REG_CAP_GUARANTEE_SCH_SKEY = FSI_CAP_GUAR_SCHEME_RECLASS.N_REG_CAP_GUARANTEE_SCH_SKEY AND STG_LEASES_CONTRACTS.FIC_MIS_DATE BETWEEN DIM_REG_CAP_GUARANTEE_SCHEME.D_RECORD_START_DATE AND DIM_REG_CAP_GUARANTEE_SCHEME.D_RECORD_END_DATE LEFT OUTER JOIN DIM_REPAYMENT_TYPE ON DIM_REPAYMENT_TYPE.V_REPAYMENT_TYPE = STG_LEASES_CONTRACTS.V_REPAYMENT_TYPE AND STG_LEASES_CONTRACTS.FIC_MIS_DATE BETWEEN DIM_REPAYMENT_TYPE.D_RECORD_START_DATE AND DIM_REPAYMENT_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_PARTY_GRADE_RECLASS ON FSI_PARTY_GRADE_RECLASS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY AND FSI_PARTY_GRADE_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_PARTY_GRADE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_GRADE_RECLASS.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY WHERE 1=1 AND STG_LEASES_CONTRACTS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND coalesce(FCT_ENTITY_INFO.f_cap_consl_entity_ind, 'N') = 'Y' AND DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code IN ( 'FLCS' ,'PRCS' ) AND FCT_ENTITY_INFO.n_run_skey = '870' AND FCT_ENTITY_INFO.n_mis_date_skey = DIM_DATES.n_Date_Skey AND coalesce(STG_LEASES_CONTRACTS.F_SECURITIZED_FLAG, 'N') <> 'Y' AND STG_LEASES_CONTRACTS.D_ACCT_CLOSED_DATE >= STG_LEASES_CONTRACTS.FIC_MIS_DATE AND EXISTS ( SELECT 1 FROM FSI_CAP_ACCOUNT_LOAD_RUN_MAP WHERE FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_ACCOUNT_NUMBER  = DIM_EXPOSURE.V_EXPOSURE_ID AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_LOAD_RUN_ID = STG_LEASES_CONTRACTS.N_LOAD_RUN_ID) AND STG_LEASES_CONTRACTS.V_DATA_JURISDICTION='BASEL' LOG ERRORS INTO FSI_CAP_BANKING_EXPOSURES$ ('1776768368425_59980894_20260331_1_Job_d6da06dc8d254aa9b0389b278a1a86b2') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
